import{_ as t,o as r,c as i,a2 as e}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"公司行动","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/corporate-actions/index.md","filePath":"zh-CN/stock-trading/corporate-actions/index.md"}'),o={name:"stock-trading/corporate-actions/index.md"};function n(l,a,s,c,d,h){return r(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="公司行动" tabindex="-1">公司行动 <a class="header-anchor" href="#公司行动" aria-label="Permalink to &quot;公司行动&quot;">​</a></h1><p>本章节说明长桥对各类公司行动的处理规则，包括现金分红、特殊派息、股票股利（送股）、供股（配股）、选股选息、拆股与合股的操作流程与注意事项。</p><h2 id="为什么要了解公司行动" tabindex="-1">为什么要了解公司行动 <a class="header-anchor" href="#为什么要了解公司行动" aria-label="Permalink to &quot;为什么要了解公司行动&quot;">​</a></h2><p>当你持有的股票发生<strong>分红</strong>、<strong>配送股</strong>、<strong>拆合股</strong>等事件时，这些都是公司行动。长桥会自动处理大部分动作（如现金分红自动入账），但某些行动（如供股、选股选息）需要你<strong>主动应对</strong>——否则可能失去收益或承受其他影响。</p><p><strong>关键场景</strong>：</p><ul><li>你持有的股票有分红 → 需要了解如何收取，是否有税务影响</li><li>公司送股或配股 → 需要了解你是否有权利、如何行使</li><li>公司拆股或合股 → 持仓数量会变，需要知道交易有什么影响</li></ul><h2 id="本章导航" tabindex="-1">本章导航 <a class="header-anchor" href="#本章导航" aria-label="Permalink to &quot;本章导航&quot;">​</a></h2><h3 id="现金与股息相关" tabindex="-1">现金与股息相关 <a class="header-anchor" href="#现金与股息相关" aria-label="Permalink to &quot;现金与股息相关&quot;">​</a></h3><ul><li><a href="/wiki/stock-trading/corporate-actions/dividend">派息</a> — 现金分红的结算、税务、时间线</li><li><a href="/wiki/stock-trading/corporate-actions/scrip-dividend">选股选息</a> — 送股权利、选股选息规则、权益登记日</li></ul><h3 id="融资与股本变动" tabindex="-1">融资与股本变动 <a class="header-anchor" href="#融资与股本变动" aria-label="Permalink to &quot;融资与股本变动&quot;">​</a></h3><ul><li><a href="/wiki/stock-trading/corporate-actions/rights-issue">供股要约</a> — 供股权获取、行使、交易、放弃规则</li><li><a href="/wiki/stock-trading/corporate-actions/stock-split">拆合股</a> — 拆股合股对持仓与交易的影响</li></ul><h3 id="股东会议" tabindex="-1">股东会议 <a class="header-anchor" href="#股东会议" aria-label="Permalink to &quot;股东会议&quot;">​</a></h3><ul><li><a href="/wiki/stock-trading/corporate-actions/general-meeting">股东大会</a> — 股东大会类型、参与资格、投票机制</li></ul><h3 id="风险管理" tabindex="-1">风险管理 <a class="header-anchor" href="#风险管理" aria-label="Permalink to &quot;风险管理&quot;">​</a></h3><ul><li><a href="/wiki/stock-trading/corporate-actions/impact-on-orders">长期订单影响</a> — 分红、拆合股对 GTC/GTD 单的影响</li></ul>',15)])])}const k=t(o,[["render",n]]);export{p as __pageData,k as default};
